function ModelResonance:GetMapHeroIdById(heroId)
	local heroData = gModelHero:GetHeroById(heroId)
	return heroData~= nil and heroId or "0"
end

function ModelResonance:OnResonanceHeroMapResp(pb,ret)
	local getMapData = function(mapData)
		local data = {slotRefId = mapData.slotRefId,
					  sourceHeroId =self:GetMapHeroIdById(mapData.sourceHeroId) ,
					  targetHeroId =self:GetMapHeroIdById(mapData.targetHeroId),}
		return	data
	end
	local mappings = pb.heroMap
	if(not mappings)then
		return
	end
	--local list = {}
	local targetDict = {}
	self.heroMappings = self.heroMappings or {}
	for i, v in ipairs(mappings) do
		local data = getMapData(v)
		if(data.targetHeroId and data.targetHeroId~="0")then
			targetDict[data.targetHeroId] = data
		end
		local isSet = false
		for j, k in ipairs(self.heroMappings) do
			if(k.slotRefId == data.slotRefId)then
				self.heroMappings[j] = data
				isSet = true
			end
		end
		if(not isSet)then
			table.insert(self.heroMappings,data)
		end
	end
	--self.heroMappings = list
	self.targetMappingDict = targetDict
	FireEvent(EventNames.ON_REFRESH_MAPPINGS)
end
function ModelResonance:CheckHeroInMappings(heroId,curHeroId,checkSource)
	local mappings = self.heroMappings
	if(not mappings or #mappings <=0 or heroId==curHeroId)then
		return
	end
	for i, v in ipairs(mappings) do
		local vSourceHeroId = self:GetMapHeroIdById(v.sourceHeroId)
		local vTargetHeroId = self:GetMapHeroIdById(v.targetHeroId)
		local isSource = checkSource and heroId == vSourceHeroId or false
		local isTarget = heroId == vTargetHeroId
		if(isSource or isTarget)then
			return true
		end
	end
end
function ModelResonance:GetHeroMappings()
	return self.heroMappings or {}
end
function ModelResonance:GetTargetMappingDict()
	return self.targetMappingDict or {}
