function ModelResonance:CheckHeroInTargetMappingDict(heroId)
	local dict = self:GetTargetMappingDict()
	local heroData = self:GetMapHeroIdById(heroId)
	return heroData and dict[heroId] or nil
end
function ModelResonance:GetMappingOtherId(heroId)
	local mappings = self.heroMappings
	if(not mappings or #mappings <=0)then
		return
	end
	for i, v in ipairs(mappings) do
		local isSource = heroId == v.sourceHeroId
		if(isSource)then
			local heroId = v.targetHeroId
			heroId = (heroId and heroId~=0 and heroId~="0") and heroId or nil
			local heroData = self:GetMapHeroIdById(heroId)
			return heroData and heroId or nil
		end
		local isTarget = heroId == v.targetHeroId
		if(isTarget)then
			local heroId = v.sourceHeroId
			heroId = (heroId and heroId~=0 and heroId~="0") and heroId or nil
			local heroData = self:GetMapHeroIdById(heroId)
			return heroData and heroId or nil
		end
	end
end
