function ModelResonance:CheckListHasMappingHero(heroId,heroList,idRecord)
	local otherId = gModelResonance:GetMappingOtherId(heroId)
	if(heroList)then
		for i, v in pairs(heroList) do
			if(i == otherId)then
				return true
			end
		end
	end
	if(idRecord)then
		for i, v in pairs(idRecord) do
			if(i == otherId)then
				return true
			end
		end
	end
end

