function ModelResonance:OnResonanceInfoResp(pb,ret)
	self._heroResonanceList = {}
	self._heroResonancePosList = {}
	self._heroResonanceHeroList = {}
	self._heroResonanceHeroKeyList = {}
	local info = pb.info
	local offerHeroIds = info.offerHeroIds
	local level,maxLevel = info.level,info.maxLevel
	local pos = info.pos
	for i,v in ipairs(offerHeroIds) do
		table.insert(self._heroResonanceList,v)
	end
	local tupoLimit = GameTable.LevelShareConfigRef["resonanceBreachLevel"]
	local oldLevel = self._resonanceLevel
	self._resonanceLevel = level
	-- if level == tupoLimit then【G公共支持】删除伙伴晶石功能相关数据
	-- 	FireEvent(EventNames.ON_CRYSTAL_REACH)
	-- end

	-- 显示突破特效
	if self._showTuPoEff == -1 and level >= tupoLimit and oldLevel and oldLevel < tupoLimit then
		self._showTuPoEff = 1
	end

	self._resonanceMaxLevel = maxLevel
	for i,v in ipairs(pos) do
        local refId,heroId = v.refId,v.heroId
		self._heroResonancePosList[refId] = {refId = refId,heroId = heroId,coolTime = v.coolTime}
		--table.insert(heroResonancePosList,{refId = v.refId,heroId = v.heroId,coolTime = v.coolTime})
		self._heroResonanceHeroKeyList[heroId] = refId

		table.insert(self._heroResonanceHeroList,{refId = refId,heroId = heroId,coolTime = v.coolTime})
	end
	FireEvent(EventNames.ON_RED_POINT_CHANGE,ModelRedPoint.HERO_RESONANCE_TUPO)
end

