function ModelResonance:SelResonanceHeroList()
	local resonanceList = {}
	local heroResonanceList = self:GetHeroResonanceList()
	local heroResonancePosList = self:GetHeroResonancePosList()
	for k,v in pairs(heroResonanceList) do resonanceList[v] = v end
	for k,v in pairs(heroResonancePosList) do
		if not string.isempty(v.heroId) then
			resonanceList[v.heroId] = v.heroId
		end
	end
	return resonanceList
end

