function ModelResonance:CheckResonanceRedPoint()
	local checkEmptyPos = true
	local heroResonancePosList = self:GetHeroResonancePosList()
	local resonanceShowItem = GameTable.LevelShareConfigRef["resonanceShowItem"]
	local num = gModelItem:GetNumByRefId(resonanceShowItem)
	local maxPos = 0
	local isEmpty = false
	local haveCoolTimeGridNum = 0
	if checkEmptyPos then
		for k,v in pairs(heroResonancePosList) do
			local ref = GameTable.LevelSharePosRef[k]
			if ref then
				local nextId = ref.nextId
				if nextId > maxPos then
					maxPos = nextId
				end
			end

			if v.coolTime ~= nil then
				haveCoolTimeGridNum = haveCoolTimeGridNum + 1
			end
		end
	else
		for k,v in pairs(heroResonancePosList) do
			if isEmpty then break end
			local heroId = v.heroId
			if heroId  == "" and tonumber(v.coolTime) == 0 then
				isEmpty = true
			end
			local ref = GameTable.LevelSharePosRef[k]
			if ref then
				local nextId = ref.nextId
				if nextId > maxPos then
					maxPos = nextId
				end
			end

			if v.coolTime ~= nil then
				haveCoolTimeGridNum = haveCoolTimeGridNum + 1
			end
		end
	end

	--日服增加消失规则：解锁共鸣格数大于15后不显示
	if gLGameLanguage:IsJapanRegion() and haveCoolTimeGridNum > 15 then
		return false
	end

	if isEmpty then
		local canSel = false
		local resonanceList = self:SelResonanceHeroList()
		local heroList = gModelHero:GetHeroList()
		for k,v in pairs(heroList) do
			if canSel then break end
			local hero = v:GetServerData()
			local id = hero.id
			if not resonanceList[id] then
				local lv = hero.lv
				if lv < self._resonanceLevel then
					canSel = true
				end
			end
		end
		isEmpty = canSel
	end
	if isEmpty then return isEmpty end
	if maxPos == 0 or maxPos == -1 then
		return false
	else
		local ref = GameTable.LevelSharePosRef[maxPos]
		local nextId = ref.nextId
		if nextId ~= -1 then
			local unlockNeedItem = ref.unlockNeedItem
			if not string.isempty(unlockNeedItem) then
				unlockNeedItem = string.split(unlockNeedItem,"=")
				local needNum = tonumber(unlockNeedItem[3])
				return num >= needNum
			end
		end
	end
	return false
end

function ModelResonance:CheckResonanceEnough()
	local heroResonancePosList = self:GetHeroResonancePosList()
	local resonanceShowItem = GameTable.LevelShareConfigRef["resonanceShowItem"]
	local num = gModelItem:GetNumByRefId(resonanceShowItem)
	local maxPos = 0
	local unlockNeedItem = ""
	for k,v in pairs(heroResonancePosList) do
		local ref = GameTable.LevelSharePosRef[k]
		if ref then
			local nextId = ref.nextId
			if nextId > maxPos then
				maxPos = nextId
				local nextNeed = GameTable.LevelSharePosRef[maxPos]
				if nextNeed then
					unlockNeedItem = nextNeed.unlockNeedItem
				end
			end
		end
	end
	if maxPos == 0 or maxPos == -1 then
		return false
	else
		if not string.isempty(unlockNeedItem) then
			unlockNeedItem = string.split(unlockNeedItem,"=")
			local needNum = tonumber(unlockNeedItem[3])
			return num >= needNum
		end
	end
	return false
end

function ModelResonance:InitBreakUpMaxLv()
	local maxLevel = 0
	for k,v in pairs(GameTable.LevelShareBreachRef) do
		local refId = v.refId
		if refId > maxLevel then
			maxLevel = refId
		end
	end
	self._breakUpMaxLv = maxLevel
end

function ModelResonance:GetBreakUpMaxLv()
	return self._breakUpMaxLv or 0
end

function ModelResonance:CheckBreakRedPoint()
	local resonanceBreachLevel = GameTable.LevelShareConfigRef["resonanceBreachLevel"]
	local resonanceLevel = self:GetResonanceLv()
	local resonanceMaxLevel = self:GetResonanceMaxLv()
	if resonanceLevel < resonanceBreachLevel then
		return false
	elseif resonanceLevel == resonanceMaxLevel then
		return false
	else
		local ref = GameTable.LevelShareBreachRef[resonanceLevel]
		if ref then
			local upNeed = ref.upNeed
			if string.isempty(upNeed) then
				return false
			else
				local showRedPoint = true
				if upNeed == "-1" then
					showRedPoint = false
				else
					if resonanceLevel < resonanceMaxLevel then
						upNeed = string.split(upNeed,",")
						for i,v in ipairs(upNeed) do
							if not showRedPoint then break end
							v = string.split(v,"=")
							local needRedId,needNum = tonumber(v[2]),tonumber(v[3])
							local bagHave = gModelItem:GetNumByRefId(needRedId)
							showRedPoint = bagHave >= needNum
						end
					else
						showRedPoint = false
					end
				end
				return showRedPoint
			end
		else
			return false
		end
	end
	return false
end

function ModelResonance:CheckMappingRedPoint()
	local mapPosRef = GameTable.ResonanceHeroMapPosRef
	for i, v in pairs(mapPosRef) do
		local funcId = v.functionOpen
		if(funcId)then
			local isOpen = gModelFunctionOpen:CheckIsOpened(funcId)
			local mappingRedRecord = LPlayerPrefs.mappingRedRecord
			if(isOpen and not toboolean(mappingRedRecord))then
				return true
			end
		end
	end
end

